        adaptor.read(sensor_id); // Read sensor_id directly

        for (auto& temp : temperatures) {
            float value;
            adaptor.read(value);
            hexi::endian::little_to_native_inplace(value);
            temp = value;
        }

        double value;
        adaptor.read(value);
        hexi::endian::little_to_native_inplace(value);
        pressure = value;
    }
